mapper.select:


    h.del_flag = '0'

        AND h.project_id = #{house.projectId}


        AND h.building_id = #{house.buildingId}


        AND h.unit_id = #{house.unitId}


        AND h.house_code LIKE CONCAT('%', #{house.houseCode}, '%')


        AND h.house_no LIKE CONCAT('%', #{house.houseNo}, '%')


        AND h.house_type_name = #{house.houseTypeName}


        AND h.house_status = #{house.houseStatus}


        AND h.is_featured = #{house.isFeatured}


        AND h.status = #{house.status}


ORDER BY h.create_time DESC
